{% comment %}
    Barre de symptômes sticky avec indicateur de scroll
{% endcomment %}
<div class="symptoms-section-wrapper">
    <div class="symptoms-sticky-bar">
        <div class="symptoms-container" id="symptomsContainer">
            <div class="symptom-badge">Acne</div>
            <div class="symptom-badge">Irregular Periods</div>
            <div class="symptom-badge">Hair Loss</div>
            <div class="symptom-badge">Hirsutism</div>
            <div class="symptom-badge">Weight Gain</div>
            <div class="symptom-badge">Mood Swings</div>
            <div class="symptom-badge">Fatigue</div>
            <div class="symptom-badge">Insulin Resistance</div>
        </div>

        <!-- Indicateur de scroll à droite -->
        <div class="scroll-indicator scroll-right" id="scrollRight">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <polyline points="9 18 15 12 9 6"></polyline>
            </svg>
        </div>
    </div>
</div>

<style>
/* ============================================= */
/* Section Symptômes avec indicateur de scroll */
/* ============================================= */
.symptoms-section-wrapper {
    width: 100%;
    margin: 0 ;
    padding: 0;
}

.symptoms-sticky-bar {
    position: sticky;
    top: -1.2rem;
    z-index: 100;
    background: linear-gradient(180deg, #fff 0%, #fefaf8 100%);
    border-bottom: 2px solid #f4d4cc;
    box-shadow: 0 2px 7px rgba(212, 137, 125, 0.08);
    padding: 10px 0;
    margin-bottom: -2.2rem;
    position: relative;
}

.symptoms-container {
    display: flex;
    gap: 10px;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    padding: 0 5px;
    scrollbar-width: none;
    -ms-overflow-style: none;
    scroll-behavior: smooth;
}

.symptoms-container::-webkit-scrollbar {
    display: none;
}

.symptom-badge {
    background: #fef7f5;
    border: 1.3px solid #f44b32;
    color: #f44b32;
    font-size: 0.50rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.3px;
    border-radius: 20px;
    padding: 8px 16px;
    white-space: nowrap;
    flex-shrink: 0;
    transition: all 0.2s ease;
    cursor: default;
}

.symptom-badge:hover {
    background: #f44b32;
    color: #fff;
    border-color: #d4897d;
    transform: translateY(-1px);
}

/* Indicateur de scroll */
.scroll-indicator {
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    width: 32px;
    height: 32px;
    background: #f44b32;
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 4px 10px rgba(212, 137, 125, 0.3);
    z-index: 10;
}

.scroll-indicator.scroll-right {
    right: 10px;
}

.scroll-indicator:hover {
    background: rgba(212, 137, 125, 1);
    transform: translateY(-50%) scale(1.1);
}

.scroll-indicator.hidden {
    opacity: 0;
    pointer-events: none;
}

/* Animation pulse pour attirer l'attention */
@keyframes pulse {
    0%, 100% {
        box-shadow: 0 2px 9px rgba(212, 137, 125, 0.3);
    }
    50% {
        box-shadow: 0 2px 16px rgba(212, 137, 125, 0.6);
    }
}

.scroll-indicator:not(.hidden) {
    animation: pulse 2s ease-in-out infinite;
}

/* Effet fade sur les bords */
.symptoms-sticky-bar::before {
    content: "";
    position: absolute;
    top: 0;
    bottom: 0;
    left: 0;
    width: 40px;
    background: linear-gradient(90deg, #fff 0%, transparent 100%);
    pointer-events: none;
    z-index: 2;
}

.symptoms-sticky-bar::after {
    content: "";
    position: absolute;
    top: 0;
    bottom: 0;
    right: 0;
    width: 40px;
    background: linear-gradient(270deg, #fefaf8 0%, transparent 100%);
    pointer-events: none;
    z-index: 2;
    opacity: 0.5;
}

/* Responsive */
@media (max-width: 768px) {
    .symptoms-sticky-bar {
        padding: 10px 0;
    }

    .symptoms-container {
        gap: 5px;
        padding: 0 2px;
    }

    .symptom-badge {
        font-size: 0.50rem;
        padding: 4px 8px;
    }

    .scroll-indicator {
        width: 28px;
        height: 28px;
    }

    .scroll-indicator svg {
        width: 16px;
        height: 16px;
    }
}

/* Animation d'entrée */
@keyframes fadeInDown {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.symptoms-sticky-bar {
    animation: fadeInDown 0.3s ease;
}
</style>

<script>
// Gestion de l'indicateur de scroll
document.addEventListener('DOMContentLoaded', function() {
    const container = document.getElementById('symptomsContainer');
    const scrollRight = document.getElementById('scrollRight');

    function updateScrollIndicator() {
        const maxScroll = container.scrollWidth - container.clientWidth;
        const currentScroll = container.scrollLeft;

        // Cache l'indicateur si on est à la fin ou s'il n'y a pas de scroll
        if (maxScroll <= 0 || currentScroll >= maxScroll - 10) {
            scrollRight.classList.add('hidden');
        } else {
            scrollRight.classList.remove('hidden');
        }
    }

    // Scroll au clic sur l'indicateur
    scrollRight.addEventListener('click', function() {
        container.scrollBy({
            left: 200,
            behavior: 'smooth'
        });
    });

    // Vérifie au chargement et au scroll
    updateScrollIndicator();
    container.addEventListener('scroll', updateScrollIndicator);
    window.addEventListener('resize', updateScrollIndicator);
});
</script>

