  0%, 100% { box-shadow: 0 0 0 0 rgba(217, 119, 6, 0.4); }
  50% { box-shadow: 0 0 0 4px rgba(217, 119, 6, 0.1); }
}

.bundle-variant:first-child .bundle-input:checked + .bundle-label {
  animation: pulse-border 2s infinite;
}

